import{_ as e,o as i,c as a,a2 as l}from"./chunks/framework.D36jym0Z.js";const p=JSON.parse('{"title":"Plugins","description":"","frontmatter":{},"headers":[],"relativePath":"platform-concepts/plugins.md","filePath":"platform-concepts/plugins.md","lastUpdated":1784542960000}'),n={name:"platform-concepts/plugins.md"};function o(s,t,r,d,c,g){return i(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="plugins" tabindex="-1">Plugins <a class="header-anchor" href="#plugins" aria-label="Permalink to &quot;Plugins&quot;">​</a></h1><p>Plugins are <strong>reusable agent capabilities</strong> that run on the LightMem2 platform. Each plugin provides one well-scoped capability — context management, memory, or future features — and works across all supported hosts.</p><h2 id="plugin-model" tabindex="-1">Plugin Model <a class="header-anchor" href="#plugin-model" aria-label="Permalink to &quot;Plugin Model&quot;">​</a></h2><p>A plugin is a self-contained package with:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Component</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Manifest</strong></td><td style="text-align:left;">Metadata: ID, version, compatible hosts, permissions needed</td></tr><tr><td style="text-align:left;"><strong>Configuration schema</strong></td><td style="text-align:left;">Declares what settings the plugin accepts, with types and defaults</td></tr><tr><td style="text-align:left;"><strong>Lifecycle hooks</strong></td><td style="text-align:left;">Functions called by the runtime at specific points (install, enable, disable, etc.)</td></tr><tr><td style="text-align:left;"><strong>Runtime logic</strong></td><td style="text-align:left;">The actual behavior: intercepting messages, transforming context, managing state</td></tr></tbody></table><h2 id="current-plugins" tabindex="-1">Current Plugins <a class="header-anchor" href="#current-plugins" aria-label="Permalink to &quot;Current Plugins&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Plugin</th><th style="text-align:left;">Capability</th><th style="text-align:left;">Status</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/LightMem2/plugin-catalog/tokenpilot/overview">TokenPilot</a></td><td style="text-align:left;">Cache-aware context management</td><td style="text-align:left;">Stable</td></tr><tr><td style="text-align:left;">Memory Plugin</td><td style="text-align:left;">Long-term memory</td><td style="text-align:left;"><span class="badge-experimental">experimental</span></td></tr></tbody></table><h2 id="plugin-specification" tabindex="-1">Plugin Specification <a class="header-anchor" href="#plugin-specification" aria-label="Permalink to &quot;Plugin Specification&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Under development</p><p>The formal plugin specification (unique IDs, versioning, compatibility ranges, dependency rules, and security declarations) is being defined by the core team. The sections below describe the current working model based on the TokenPilot implementation.</p></div><h3 id="plugin-identity" tabindex="-1">Plugin Identity <a class="header-anchor" href="#plugin-identity" aria-label="Permalink to &quot;Plugin Identity&quot;">​</a></h3><ul><li>Each plugin has a <strong>unique ID</strong> (e.g., <code>tokenpilot</code>)</li><li>Plugins declare a <strong>version</strong> following semver</li><li>Plugins declare <strong>compatible LightMem2 core versions</strong></li></ul><h3 id="host-compatibility" tabindex="-1">Host Compatibility <a class="header-anchor" href="#host-compatibility" aria-label="Permalink to &quot;Host Compatibility&quot;">​</a></h3><p>A plugin declares which hosts it supports. TokenPilot currently supports:</p><ul><li>OpenClaw</li><li>Codex</li><li>Claude Code</li></ul><p>A plugin may support a subset of hosts. The runtime checks compatibility at load time.</p><h3 id="data-access" tabindex="-1">Data Access <a class="header-anchor" href="#data-access" aria-label="Permalink to &quot;Data Access&quot;">​</a></h3><p>Plugins declare what data they need to read and write. This is used for:</p><ul><li>Permission prompts during install</li><li>Conflict detection between plugins</li><li>Privacy and security review</li></ul><p>TokenPilot, for example, reads:</p><ul><li>Message history and tool outputs</li><li>Session metadata</li><li>Configuration files</li></ul><p>And writes:</p><ul><li>Modified context (stable-prefix rewriting)</li><li>Session metrics and reports</li><li>Configuration state</li></ul><h2 id="what-makes-a-good-plugin" tabindex="-1">What Makes a Good Plugin <a class="header-anchor" href="#what-makes-a-good-plugin" aria-label="Permalink to &quot;What Makes a Good Plugin&quot;">​</a></h2><ul><li><strong>Single responsibility</strong>. One plugin, one capability. Compose, don&#39;t overload.</li><li><strong>Host-independent</strong>. Core logic should not import host-specific APIs.</li><li><strong>Declarative config</strong>. Expose settings through a typed schema, not ad-hoc env vars.</li><li><strong>Observable</strong>. Export metrics so users can see what the plugin is doing.</li></ul><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/LightMem2/platform-concepts/plugin-lifecycle">Plugin Lifecycle</a> — the state machine</li><li><a href="/LightMem2/plugin-catalog/tokenpilot/overview">TokenPilot Overview</a> — see a real plugin</li><li><a href="/LightMem2/plugin-development/build-your-first-plugin">Build Your First Plugin</a> — start developing</li></ul>',26)])])}const h=e(n,[["render",o]]);export{p as __pageData,h as default};
